// O n8n passa os itens um a um ou o array completo dependendo da configuração.
// Para garantir que pegamos a lista dentro de 'output':
const items =$input.first().json.output ;

// Verificar se 'output' existe e é uma lista
if (!Array.isArray(items)) {
  return [{
    json: {
      error: "A propriedade 'output' não foi encontrada ou não é uma lista.",
      receivedData: $json
    }
  }];
}

// Mapear cada pessoa da lista para o novo formato
return items.map(item => {
  return {
    json: {
      newNOME: item.nome ? item.nome.toUpperCase() : "N/A",
      // Remove pontos, traços e espaços do CPF
      newCPF: item.cpf ? item.cpf.replace(/[\.\-\s]/g, '') : "N/A",
      // Remove espaços do celular
      newTELEFONE: item.celular ? item.celular.replace(/\s/g, '') : "N/A",
      newDTNASCIMENTO: item.nascimento || "N/A",
      newCARGO: item.cargo || "N/A",
      newEMPRESA: item.empresa || "N/A",
      newDTADMISSAO: item.inicio || "N/A",
    }
  };
});

// Obtenha as listas filtrando os itens que possuem as chaves específicas
const listOfAll = $('CombinedItems').all().filter(item => item.json.CPF !== undefined);
const listOfDisableds = $('CombinedItems').all().filter(item => item.json.newCPF !== undefined);

// Inicializa um array vazio para armazenar os resultados
let listaGeral = [];

// Função para verificar se o nome existe na lista de ativos
function foundName(cpf) {
  return listOfAll.some(item => cpf === item.json.CPF);
}

// Loop pelos nomes desligados e adiciona ao array listaGeral
for (const disabled of listOfDisableds) {
  listaGeral.push({
    newCPF: disabled.json.newCPF,
    newNOME: disabled.json.newNOME.trim(),
    newTELEFONE: disabled.json.newTELEFONE,
    newCARGO: disabled.json.newCARGO.trim(),
    newEMPRESA: disabled.json.newEMPRESA,
    newDTADMISSAO: disabled.json.newDTADMISSAO,
    newDTNASCIMENTO: disabled.json.newDTNASCIMENTO,
    status: foundName(disabled.json.newCPF),
    local: disabled.json.LOCAL // Adiciona o local ao resultado
  });
}

// Retorna os resultados como um array
return listaGeral;

// Entradas
const usuariosData = $('separaExitente').all(); // Lista de dados de usuários recebidos
const usuariosExistentes = $('coletaDados')
    .all()
    .map(item => item.json.USUARIO)
    .filter(usuario => usuario); // Lista de usuários existentes

// Lista de palavras a serem ignoradas (preposições comuns)
const palavrasIgnoradas = ["de", "da", "do", "das", "dos"];

// Função para remover acentos
const removerAcentos = (str) =>
    str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();

// Função para gerar nomes de usuário
function gerarNomeUsuario(nomeCompleto, usuariosExistentes) {
    const nomeSemAcentos = removerAcentos(nomeCompleto);
    const partesNome = nomeSemAcentos.split(" ").filter(p => p.length > 0 && !palavrasIgnoradas.includes(p));

    const primeiroNome = partesNome[0];
    let sobrenome = partesNome[partesNome.length - 1];
    let nomeUsuario = `${primeiroNome}.${sobrenome}`;
    let tentativa = 1;

    // Tenta variações do nome até encontrar um disponível
    while (usuariosExistentes.includes(nomeUsuario)) {
        if (tentativa === 1 && partesNome.length > 2) {
            sobrenome = partesNome[1]; // Segundo nome como sobrenome
        } else if (tentativa === 2 && partesNome.length > 3) {
            sobrenome = `${partesNome[1]}${partesNome[2]}`; // Combina segundo nome com próximo sobrenome
        } else {
            sobrenome = `${partesNome.slice(1).join("")}${tentativa}`; // Junta todos os sobrenomes com número
        }
        nomeUsuario = `${primeiroNome}.${sobrenome}`;
        tentativa++;
    }

    return nomeUsuario;
}

// Gerar os nomes de usuário para cada entrada e incluir os dados originais
const resultados = usuariosData.map(item => {
    const nomeCompleto = item.json.newNOME;
    const nomeUsuario = gerarNomeUsuario(nomeCompleto, usuariosExistentes);

    return {
        json: {
            ...item.json,
            usuario: nomeUsuario
        }
    };
});

// Retornar os resultados
return resultados;

const items = $("IncorretosName").all();  // Pega todos os dados do campo SeparaDados

// Definição dos tamanhos mínimos para as colunas
const minNomeLength = 16; // "Nome Colaborador" tem 16 caracteres
const minCpfLength = 3;   // "CPF" tem 3 caracteres

// Variáveis para armazenar o comprimento máximo de nome e CPF
let maxNomeLength = minNomeLength;
let maxCpfLength = minCpfLength;

// Itera sobre os itens de "SeparaDados" para calcular o comprimento máximo
items.forEach(item => {
  const nome = item.json.newNOME ? item.json.newNOME : ''; 
  const cpf = item.json.newCPF ? item.json.newCPF : '';   

  // Atualiza os máximos de comprimento
  maxNomeLength = Math.max(maxNomeLength, nome.length);
  maxCpfLength = Math.max(maxCpfLength, cpf.length);
});

// A lógica para garantir que os nomes e CPFs fiquem alinhados
const nomeColumnWidth = maxNomeLength + 2; // Adiciona 2 espaços para a margem
const cpfColumnWidth = maxCpfLength + 2;   // Adiciona 2 espaços para a margem

// Inicia a tabela com o cabeçalho
let tabela = `| Nome Colaborador${' '.repeat(nomeColumnWidth - minNomeLength)}| CPF${' '.repeat(cpfColumnWidth - minCpfLength)}|\n`;
tabela += `|${'-'.repeat(nomeColumnWidth)}|${'-'.repeat(cpfColumnWidth)}|\n`;

// Itera novamente para preencher a tabela com os dados
items.forEach(item => {
  const nome = item.json.newNOME ? item.json.newNOME : 'Dado ausente'; 
  const cpf = item.json.newCPF ? item.json.newCPF : 'Dado ausente'; 

  // Adiciona os dados formatados na tabela com o número correto de espaços para garantir alinhamento
  tabela += `| ${nome.padEnd(nomeColumnWidth - 1)} | ${cpf.padEnd(cpfColumnWidth - 1)} |\n`;
});

// Cria a mensagem final
const mensagem = `Prezados,\n\nEstamos realizando a criação de acessos em nossos sistemas e identificamos que os nomes dos colaboradores não estão compatíveis com os CPFs registrados. Segue a tabela com as discrepâncias encontradas:\n\n${tabela}\nPara garantir que os dados estejam corretos, gostaríamos de validar os nomes corretamente para que possamos realizar a criação dos acessos.`;

// Retorna o JSON de forma estruturada para o campo content
return {
  json: {
    content: JSON.stringify(mensagem) // Envia o texto diretamente sem JSON.stringify
  }
};

